import React, { useState, useEffect } from 'react';
import { auth, firestore } from '../firebase';
import { collection, addDoc, onSnapshot, query, orderBy, serverTimestamp, doc, updateDoc, increment } from 'firebase/firestore';
import './Forum.css';

const Forum = () => {
  const [posts, setPosts] = useState([]);
  const [newPost, setNewPost] = useState('');
  const [newReplies, setNewReplies] = useState({});
  const [loading, setLoading] = useState(true);
  const [replies, setReplies] = useState({});

  useEffect(() => {
    const q = query(collection(firestore, 'posts'), orderBy('timestamp', 'desc'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const postsData = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      }));
      setPosts(postsData);
      setLoading(false);

      // Fetch replies for each post
      postsData.forEach(post => {
        const repliesQuery = query(
          collection(firestore, `posts/${post.id}/replies`),
          orderBy('timestamp', 'desc')
        );
        onSnapshot(repliesQuery, (repliesSnapshot) => {
          const repliesData = repliesSnapshot.docs.map(doc => ({
            id: doc.id,
            ...doc.data()
          }));
          setReplies(prev => ({
            ...prev,
            [post.id]: repliesData
          }));
        });
      });
    });

    return () => unsubscribe();
  }, []);

  const handleSubmitPost = async (e) => {
    e.preventDefault();
    if (!newPost.trim() || !auth.currentUser) return;

    try {
      await addDoc(collection(firestore, 'posts'), {
        content: newPost,
        authorId: auth.currentUser.uid,
        authorName: auth.currentUser.displayName || 'Anonymous',
        authorPhoto: auth.currentUser.photoURL || '/default-avatar.png',
        timestamp: serverTimestamp(),
        likes: 0,
        dislikes: 0
      });
      setNewPost('');
    } catch (error) {
      console.error('Error adding post:', error);
    }
  };

  const handleLike = async (postId) => {
    if (!auth.currentUser) return;
    try {
      const postRef = doc(firestore, 'posts', postId);
      await updateDoc(postRef, {
        likes: increment(1)
      });
    } catch (error) {
      console.error('Error updating likes:', error);
    }
  };

  const handleDislike = async (postId) => {
    if (!auth.currentUser) return;
    try {
      const postRef = doc(firestore, 'posts', postId);
      await updateDoc(postRef, {
        dislikes: increment(1)
      });
    } catch (error) {
      console.error('Error updating dislikes:', error);
    }
  };

  const handleSubmitReply = async (postId) => {
    if (!newReplies[postId]?.trim() || !auth.currentUser) return;

    try {
      const replyRef = collection(firestore, `posts/${postId}/replies`);
      await addDoc(replyRef, {
        content: newReplies[postId],
        authorId: auth.currentUser.uid,
        authorName: auth.currentUser.displayName || 'Anonymous',
        authorPhoto: auth.currentUser.photoURL || '/default-avatar.png',
        timestamp: serverTimestamp()
      });
      setNewReplies(prev => ({ ...prev, [postId]: '' }));
    } catch (error) {
      console.error('Error adding reply:', error);
    }
  };

  if (loading) {
    return (
      <div className="forum-container">
        <div className="loading">Loading forum posts...</div>
      </div>
    );
  }

  if (!auth.currentUser) {
    return (
      <div className="forum-container">
        <div className="forum-header">
          <h1>Community Forum</h1>
          <p>Join our community discussions about wildlife conservation.</p>
        </div>
        <div className="login-prompt">
          <p>Please log in to participate in the forum discussions.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="forum-container">
      <div className="forum-header">
        <h1>Community Forum</h1>
        <p>Join our community discussions about wildlife conservation.</p>
      </div>

      <form className="post-form" onSubmit={handleSubmitPost}>
        <textarea
          value={newPost}
          onChange={(e) => setNewPost(e.target.value)}
          placeholder="Share your thoughts..."
          rows="4"
        />
        <button type="submit" className="submit-post-button">Post</button>
      </form>

      <div className="forum-posts">
        {posts.map(post => (
          <div key={post.id} className="post">
            <div className="post-header">
              <img
                src={post.authorPhoto || '/default-avatar.png'}
                alt={post.authorName}
                className="author-avatar"
              />
              <div className="post-info">
                <strong>{post.authorName}</strong>
                <span className="timestamp">
                  {post.timestamp?.toDate().toLocaleDateString()}
                </span>
              </div>
            </div>

            <div className="post-content">
              <p>{post.content}</p>
            </div>

            <div className="post-actions">
              <button onClick={() => handleLike(post.id)}>
                👍 {post.likes || 0}
              </button>
              <button onClick={() => handleDislike(post.id)}>
                👎 {post.dislikes || 0}
              </button>
            </div>

            <div className="replies">
              {replies[post.id]?.map(reply => (
                <div key={reply.id} className="reply">
                  <div className="reply-header">
                    <img
                      src={reply.authorPhoto || '/default-avatar.png'}
                      alt={reply.authorName}
                      className="author-avatar small"
                    />
                    <div className="reply-info">
                      <strong>{reply.authorName}</strong>
                      <span className="timestamp">
                        {reply.timestamp?.toDate().toLocaleDateString()}
                      </span>
                    </div>
                  </div>
                  <p>{reply.content}</p>
                </div>
              ))}

              <div className="reply-form">
                <textarea
                  value={newReplies[post.id] || ''}
                  onChange={(e) =>
                    setNewReplies(prev => ({
                      ...prev,
                      [post.id]: e.target.value
                    }))
                  }
                  placeholder="Write a reply..."
                  rows="2"
                />
                <button
                  className="submit-reply-button"
                  onClick={() => handleSubmitReply(post.id)}
                >
                  Reply
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Forum;
